// MARK: - Transaction Processor
class TransactionProcessor {
    static let shared = TransactionProcessor()
    private var accounts: [Account] = []
    private var transactions: [Transaction] = []
    
    private init() {
        loadStoredData()
    }
    
    func processTransaction(_ transaction: Transaction) -> Result<Bool, Error> {
        guard let account = accounts.first(where: { $0.id == transaction.id }) else {
            return .failure(TransactionError.accountNotFound)
        }
        
        switch transaction.type {
        case .deposit:
            return performDeposit(transaction)
        case .withdrawal:
            return performWithdrawal(transaction, from: account)
        case .transfer:
            return performTransfer(transaction)
        case .payment:
            return performPayment(transaction, from: account)
        }
    }
    
    private func performDeposit(_ transaction: Transaction) -> Result<Bool, Error> {
        // Simulate deposit processing
        transactions.append(transaction)
        return .success(true)
    }
    
    private func performWithdrawal(_ transaction: Transaction, from account: Account) -> Result<Bool, Error> {
        guard account.balance >= transaction.amount else {
            return .failure(TransactionError.insufficientFunds)
        }
        transactions.append(transaction)
        return .success(true)
    }
    
    private func performTransfer(_ transaction: Transaction) -> Result<Bool, Error> {
        // Simulate transfer processing
        transactions.append(transaction)
        return .success(true)
    }
    
    private func performPayment(_ transaction: Transaction, from account: Account) -> Result<Bool, Error> {
        guard account.balance >= transaction.amount else {
            return .failure(TransactionError.insufficientFunds)
        }
        transactions.append(transaction)
        return .success(true)
    }
    
    func getAccountBalance(for accountId: String) -> Double? {
        return accounts.first { $0.id == accountId }?.balance
    }
    
    func getAccountTransactions(for accountId: String) -> [Transaction] {
        return transactions.filter { $0.id == accountId }
    }
    
    func addAccount(_ account: Account) {
        accounts.append(account)
        saveData()
    }
    
    private func loadStoredData() {
        // Load stored data from secure storage
        if let data = SecureDataManager.shared.secureRetrieve(key: "accounts_data"),
           let accounts = try? JSONDecoder().decode([Account].self, from: data) {
            self.accounts = accounts
        }
    }
    
    private func saveData() {
        if let data = try? JSONEncoder().encode(accounts) {
            SecureDataManager.shared.secureStore(key: "accounts_data", data: data)
        }
    }
}

// MARK: - Transaction Error
enum TransactionError: Error, LocalizedError {
