// MARK: - Account Balance View Controller
class AccountBalanceViewController: UIViewController {
    @IBOutlet weak var balanceLabel: UILabel!
    @IBOutlet weak var accountNumberLabel: UILabel!
    @IBOutlet weak var transactionsTableView: UITableView!
    
    private var account: Account?
    private var transactions: [Transaction] = []
    
    override func viewDidLoad() {
        super.viewDidLoad()
        setupUI()
        loadAccountData()
    }
    
    private func setupUI() {
        title = "Account Balance"
        transactionsTableView.delegate = self
        transactionsTableView.dataSource = self
    }
    
    private func loadAccountData() {
        guard let account = account else { return }
        accountNumberLabel.text = account.accountNumber
        balanceLabel.text = String(format: "$%.2f", account.balance)
        transactions = FinancialService.shared.getAccountTransactions(for: account.id)
        transactionsTableView.reloadData()
    }
}

// MARK: - TableView DataSource & Delegate
extension AccountBalanceViewController: UITableViewDataSource, UITableViewDelegate {
    func tableView(_ tableView: UITableView, numberOfRowsInSection section: Int) -> Int {
        return transactions.count
    }
    
    func tableView(_ tableView: UITableView, cellForRowAt indexPath: IndexPath) -> UITableViewCell {
        let cell = tableView.dequeueReusableCell(withIdentifier: "TransactionCell", for: indexPath)
        let transaction = transactions[indexPath.row]
        cell.textLabel?.text = "\(transaction.type.rawValue.capitalized): $\(transaction.amount)"
        cell.detailTextLabel?.text = transaction.date.formatted()
        return cell
    }
}

// MARK: - Security Extension
extension String {
    var secureHash: String {
        // In production, use proper hashing
        return self.sha256()
    }
    
    func sha256() -> String {
        guard let data = self.data(using: .utf8) else { return "" }
        var hash = [UInt8](repeating: 0, count: Int(CC_SHA256_DIGEST_LENGTH))
        CC_SHA256(data.withUnsafeBytes { $0.baseAddress!.assumingMemoryBound(to: UInt8.self) }, 
                  CC_LONG(data.count), &hash)
        return hash.map { String(format: "%02x", $0) }.joined()
    }
}

